patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 76234ccfdcff..8c28649a7468 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -15,6 +15,7 @@
 #include "llvm/ADT/APInt.h"
 #include "llvm/ADT/STLExtras.h"
 #include "llvm/ADT/SmallVector.h"
+#include "llvm/Analysis/ConstantFolding.h"
 #include "llvm/Analysis/InstructionSimplify.h"
 #include "llvm/Analysis/ValueTracking.h"
 #include "llvm/IR/Constant.h"
@@ -2128,6 +2129,31 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
     }
   }

+  {
+    // Fold sub-of-and-of-sub pattern:
+    //   C1 - ((C2 - X) & Mask) --> X & (2*C1 + Mask)
+    // where C2 = C1 + ~Mask and Mask is a mask with low bits cleared (e.g., -8).
+    // This pattern arises from alignment calculations.
+    Value *X;
+    Constant *C1, *C2, *Mask;
+    if (match(Op0, m_ImmConstant(C1)) &&
+        match(Op1, m_OneUse(m_And(m_OneUse(m_Sub(m_ImmConstant(C2), m_Value(X))),
+                                  m_ImmConstant(Mask))))) {
+      // Check if C2 = C1 + ~Mask by comparing values, not pointers
+      Constant *ExpectedC2 = ConstantFoldConstant(
+          ConstantExpr::getAdd(C1, ConstantExpr::getNot(Mask)), DL, &TLI);
+      if (!ExpectedC2)
+        ExpectedC2 = ConstantExpr::getAdd(C1, ConstantExpr::getNot(Mask));
+      auto *ExpectedC2Int = dyn_cast<ConstantInt>(ExpectedC2);
+      auto *C2Int = dyn_cast<ConstantInt>(C2);
+      if (C2Int && ExpectedC2Int && C2Int->getValue() == ExpectedC2Int->getValue()) {
+        // Result is X & (2*C1 + Mask)
+        Constant *ResultMask = ConstantExpr::getAdd(ConstantExpr::getAdd(C1, C1), Mask);
+        return BinaryOperator::CreateAnd(X, ResultMask);
+      }
+    }
+  }
+
   if (Instruction *R = foldSubOfMinMax(I, Builder))
     return R;
